+    local procedure PopulateTempWhseItemTrkgLineFromReservation(LocationCode: Code[10]; SourceID: Code[20]; SourceType: Integer; SourceBatchName: Code[10]; SourceProdOrderLine: Integer; SourceRefNo: Integer)
+    var
