+                TempWhseItemTrackingLine."Location Code" := ReservationEntry."Location Code";
+                TempWhseItemTrackingLine."Item No." := ReservationEntry."Item No.";
+                TempWhseItemTrackingLine."Variant Code" := ReservationEntry."Variant Code";
+                TempWhseItemTrackingLine."Qty. per Unit of Measure" := ReservationEntry."Qty. per Unit of Measure";
+                TempWhseItemTrackingLine.CopyTrackingFromReservEntry(ReservationEntry);
+                TempWhseItemTrackingLine."Source Type" := SourceType;
+                TempWhseItemTrackingLine."Source Subtype" := CurrSourceSubType;
+                TempWhseItemTrackingLine."Source ID" := SourceID;
+                TempWhseItemTrackingLine."Source Batch Name" := SourceBatchName;
+                TempWhseItemTrackingLine."Source Prod. Order Line" := SourceProdOrderLine;
+                TempWhseItemTrackingLine."Source Ref. No." := SourceRefNo;
+                TempWhseItemTrackingLine."Expiration Date" := ReservationEntry."Expiration Date";
+                TempWhseItemTrackingLine."Warranty Date" := ReservationEntry."Warranty Date";
+                TempWhseItemTrackingLine.Validate("Quantity (Base)", QtyToHandleBase);
+                TempWhseItemTrackingLine.Validate("Qty. to Handle (Base)", QtyToHandleBase);
+                TempWhseItemTrackingLine.Validate(Quantity, QtyToHandle);
+                TempWhseItemTrackingLine.Insert();
+
+                LastWhseItemTrkgLineNo := TempWhseItemTrackingLine."Entry No.";
+                WhseItemTrkgExists := true;
+                WhseItemTrkgLineCount += 1;
+            until ReservationEntry.Next() = 0;
+    end;
